import{_ as e,o as t,c as o,O as a}from"./chunks/framework.bdcb0ee1.js";const g=JSON.parse('{"title":"Shoutbox","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/shoutbox.md","filePath":"administration/config/shoutbox.md","lastUpdated":1773166683000}'),s={name:"administration/config/shoutbox.md"},n=a('<h1 id="shoutbox" tabindex="-1">Shoutbox <a class="header-anchor" href="#shoutbox" aria-label="Permalink to &quot;Shoutbox&quot;">​</a></h1><p>The Shoutbox is a lightweight live chat feature that appears on the board homepage. It allows members to send quick public messages without creating a full topic.</p><p>You can configure the Shoutbox from the <strong>Board Config</strong> section of the Admin Control Panel.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><ul><li><strong>Enabled?</strong>: Toggle to turn the Shoutbox on or off.</li><li><strong>Placement</strong>: Choose where the Shoutbox appears: <ul><li><strong>Top</strong>: Appears above the main content on the homepage.</li><li><strong>Bottom</strong>: Appears below the main content on the homepage.</li></ul></li><li><strong>Title</strong>: The heading shown above the Shoutbox. You can rename this to suit your community tone.</li><li><strong>Rules</strong>: Optional text shown beneath the shout input. This text appears in a modal when users click the “Rules” link next to the Shoutbox title. BBCode is supported here.</li></ul><img width="1938" height="695" alt="image" src="https://github.com/user-attachments/assets/3115ae44-ce7f-4722-b613-4c0a79f859c6"><h2 id="embedding-the-shoutbox-in-themes" tabindex="-1">Embedding the Shoutbox in Themes <a class="header-anchor" href="#embedding-the-shoutbox-in-themes" aria-label="Permalink to &quot;Embedding the Shoutbox in Themes&quot;">​</a></h2><p>You can also render the Shoutbox manually in custom themes using the special theme token:</p><p><code>&lt;!-- SHOUTBOX --&gt;</code></p><p>This is useful if you want to place the Shoutbox in a sidebar, header block, or anywhere else in your layout.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Shouts are not threaded or paginated. The most recent messages are shown first.</li><li>All users can view the Shoutbox, but posting may be limited based on group permissions.</li><li>Moderators can delete shouts via inline controls.</li><li>If you’ve defined any <strong>emoticons</strong>, they will also be shown in a modal accessible from the Shoutbox interface.</li></ul>',12),i=[n];function h(r,l,u,c,d,m){return t(),o("div",null,i)}const p=e(s,[["render",h]]);export{g as __pageData,p as default};
